import{gt as e,nt as t,s as n,tt as r}from"./chunks/framework.BqU7tCwc.js";var i=JSON.parse(`{"title":"Codex 安装与快速开始","description":"使用官方桌面端或 Codex CLI 安装、登录并开始第一个本地项目任务。","frontmatter":{"title":"Codex 安装与快速开始","description":"使用官方桌面端或 Codex CLI 安装、登录并开始第一个本地项目任务。"},"headers":[],"relativePath":"ai/codex-install.md","filePath":"ai/codex-install.md","lastUpdated":1784887501000}`),a={name:`ai/codex-install.md`};function o(n,i,a,o,s,c){return e(),r(`div`,null,[...i[0]||=[t(`<h1 id="codex-安装与快速开始" tabindex="-1">Codex 安装与快速开始 <a class="header-anchor" href="#codex-安装与快速开始" aria-label="Permalink to “Codex 安装与快速开始”">​</a></h1><p>Codex 可以通过桌面端或命令行使用，两种方式都建议使用同一个 ChatGPT 账号登录。如果刚开始使用，任选一种即可；桌面端和 CLI 可以共用项目目录与账号，不需要重复配置一套工作流。</p><blockquote><p>安装入口和可用性会随地区、系统和账号类型变化。桌面端优先保留下面的 Windows 安装工具；其他系统可按 <a href="https://openai.com/codex/get-started/" target="_blank" rel="noreferrer">Codex 官方入门页</a> 的当前提示安装。</p></blockquote><h2 id="选择使用方式" tabindex="-1">选择使用方式 <a class="header-anchor" href="#选择使用方式" aria-label="Permalink to “选择使用方式”">​</a></h2><table tabindex="0"><thead><tr><th>方式</th><th>适合场景</th><th>安装入口</th></tr></thead><tbody><tr><td>桌面端</td><td>管理多个项目、查看变更、处理持续任务</td><td>Windows 使用 <a href="https://github.com/Wangnov/codex-app-mirror" target="_blank" rel="noreferrer">codex-app-mirror</a>，其他系统见 <a href="https://openai.com/codex/get-started/" target="_blank" rel="noreferrer">官方入门页</a></td></tr><tr><td>Codex CLI</td><td>在终端、编辑器终端或脚本中工作</td><td><a href="https://learn.chatgpt.com/docs/codex/cli" target="_blank" rel="noreferrer">Codex CLI 文档</a></td></tr></tbody></table><h2 id="前置准备" tabindex="-1">前置准备 <a class="header-anchor" href="#前置准备" aria-label="Permalink to “前置准备”">​</a></h2><ul><li>一个可登录 Codex 的 ChatGPT 账号，或官方界面提供的其他登录方式。</li><li>如果需要通过非大陆 App Store 获取应用或使用 Apple 内购，准备一个对应地区的 Apple ID；建议只在“媒体与购买项目”中登录，不替换主力 iCloud 账号。</li><li>使用 CLI 时，准备好终端和项目目录；采用 npm 安装时还需要可用的 Node.js 与 npm。</li></ul><h2 id="安装桌面端" tabindex="-1">安装桌面端 <a class="header-anchor" href="#安装桌面端" aria-label="Permalink to “安装桌面端”">​</a></h2><h3 id="windows-使用-codex-app-mirror" tabindex="-1">Windows：使用 <code>codex-app-mirror</code> <a class="header-anchor" href="#windows-使用-codex-app-mirror" aria-label="Permalink to “Windows：使用 codex-app-mirror”">​</a></h3><p>Windows Store 无法正常安装或更新时，使用 <a href="https://github.com/Wangnov/codex-app-mirror" target="_blank" rel="noreferrer">Wangnov/codex-app-mirror</a> 提供的桌面端安装工具。该工具是 Windows 安装的首选入口；按仓库 README 的步骤下载、安装或更新即可。</p><h3 id="macos-与其他可用系统-官方入口" tabindex="-1">macOS 与其他可用系统：官方入口 <a class="header-anchor" href="#macos-与其他可用系统-官方入口" aria-label="Permalink to “macOS 与其他可用系统：官方入口”">​</a></h3><p>打开 <a href="https://openai.com/codex/get-started/" target="_blank" rel="noreferrer">Codex 官方入门页</a> 并按页面提示下载适用于当前系统的桌面端。</p><h3 id="apple-id-与-app-store" tabindex="-1">Apple ID 与 App Store <a class="header-anchor" href="#apple-id-与-app-store" aria-label="Permalink to “Apple ID 与 App Store”">​</a></h3><p>若安装渠道或订阅流程需要使用非大陆 App Store，可准备相应地区的 Apple ID。Apple ID 用于 App Store 下载和内购；进入 Codex 后，仍使用自己的 ChatGPT 账号登录，两者不是同一个账号。</p><p>建议单独准备一个仅用于 App Store 的 Apple ID，并只在设备的“媒体与购买项目”中切换，避免影响主力 iCloud 的同步、照片和设备查找。土耳其区 Apple ID 的注册、转区、礼品卡与 ChatGPT Plus 订阅流程见：<a href="./chatgpt-plus-turkey-apple-id.html">注册土耳其区 Apple ID 订阅 ChatGPT Plus 教程</a>。</p><h2 id="安装-codex-cli" tabindex="-1">安装 Codex CLI <a class="header-anchor" href="#安装-codex-cli" aria-label="Permalink to “安装 Codex CLI”">​</a></h2><h3 id="macos-与-linux-官方安装器" tabindex="-1">macOS 与 Linux：官方安装器 <a class="header-anchor" href="#macos-与-linux-官方安装器" aria-label="Permalink to “macOS 与 Linux：官方安装器”">​</a></h3><p>官方 CLI 文档提供独立安装器：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://chatgpt.com/codex/install.sh</span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sh</span></span></code></pre></div><h3 id="使用-npm-安装" tabindex="-1">使用 npm 安装 <a class="header-anchor" href="#使用-npm-安装" aria-label="Permalink to “使用 npm 安装”">​</a></h3><p>如果已经安装 Node.js 和 npm，也可以使用 npm 安装：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @openai/codex</span></span></code></pre></div><p>Windows 用户可优先按 <a href="https://learn.chatgpt.com/docs/codex/cli" target="_blank" rel="noreferrer">Codex CLI 官方文档</a> 中的当前说明选择安装方式；通过 npm 安装时，使用 PowerShell、Windows Terminal 或编辑器内置终端即可。</p><p>安装后确认命令可用：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>如果终端提示找不到 <code>codex</code>，先重新打开终端；仍无法使用时，检查 npm 全局 bin 目录是否已加入 <code>PATH</code>。</p><h2 id="skill-与插件建议" tabindex="-1">Skill 与插件建议 <a class="header-anchor" href="#skill-与插件建议" aria-label="Permalink to “Skill 与插件建议”">​</a></h2><p>Skill 是可复用的任务流程，插件可以额外带来 Skill、工具或外部服务连接。它们会改变 Codex 可执行的能力范围，因此只从可信来源安装，并在安装前阅读说明、权限和依赖。</p><ul><li><a href="https://github.com/DietrichGebert/ponytail" target="_blank" rel="noreferrer">ponytail</a>：面向代码任务的“少做一点”工作流，适合希望减少不必要抽象和样板代码时使用。</li><li><a href="https://github.com/obra/superpowers" target="_blank" rel="noreferrer">superpowers</a>：提供一组可复用的软件开发工作流，可按项目需要挑选使用。</li></ul><p>建议一次只安装并验证一个扩展；在工作账号或企业工作区中，插件是否可用还可能受工作区策略和管理员权限限制。</p><h2 id="mcp-推荐-jetbrains-ide-索引" tabindex="-1">MCP 推荐：JetBrains IDE 索引 <a class="header-anchor" href="#mcp-推荐-jetbrains-ide-索引" aria-label="Permalink to “MCP 推荐：JetBrains IDE 索引”">​</a></h2><p><a href="https://github.com/hechtcarmel/jetbrains-index-mcp-plugin" target="_blank" rel="noreferrer">hechtcarmel/jetbrains-index-mcp-plugin</a>（IDE Index MCP Server）将 JetBrains IDE 的代码索引、跳转定义、查找引用、诊断和重构能力通过 MCP 暴露给 Codex。适合 Java、Kotlin、Python、JavaScript / TypeScript 等项目，希望 Codex 能直接使用 IntelliJ IDEA、PyCharm 或 WebStorm 的语义索引时使用。</p><h3 id="安装与连接" tabindex="-1">安装与连接 <a class="header-anchor" href="#安装与连接" aria-label="Permalink to “安装与连接”">​</a></h3><ol><li>在 JetBrains IDE 中打开 <code>Settings / Preferences</code> → <code>Plugins</code> → <code>Marketplace</code>，搜索 <strong>IDE Index MCP Server</strong> 并安装；重启 IDE 后打开目标项目。</li><li>在底部的 <strong>Index MCP Server</strong> 工具窗口中，点击 <strong>Install on Coding Agents</strong>，选择 Codex CLI 自动写入配置。</li><li>如果需要手动配置，在启动了项目的终端中执行以下命令。端口和服务名必须与当前 IDE 保持一致：</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># IntelliJ IDEA 默认配置</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> intellij-index</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:29170/index-mcp/streamable-http</span></span></code></pre></div><p>安装完成后重新启动 Codex，在任务中要求它优先使用 JetBrains MCP 查询定义、引用或 IDE 诊断即可。更多 IDE 的默认端口、工具开关和安装说明以 <a href="https://github.com/hechtcarmel/jetbrains-index-mcp-plugin" target="_blank" rel="noreferrer">项目 README</a> 为准。</p><blockquote><p>插件默认也提供重命名、移动文件、格式化等写操作。首次使用时先用只读索引功能；启用或调用修改类工具前，确认当前项目和变更范围。</p></blockquote><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to “参考资料”">​</a></h2><ul><li><a href="https://openai.com/codex/get-started/" target="_blank" rel="noreferrer">Codex 官方入门页</a></li><li><a href="https://learn.chatgpt.com/docs/codex/cli" target="_blank" rel="noreferrer">Codex CLI 文档</a></li><li><a href="https://help.openai.com/en/articles/11369540-using-codex-with-your-chatgpt-plan" target="_blank" rel="noreferrer">使用 ChatGPT 账号开始使用 Codex</a></li></ul>`,39)]])}var s=n(a,[[`render`,o]]);export{i as __pageData,s as default};